GenerateHardwareKey PROC
    ; Generates 32-byte key from CPUID, MAC, disk serial
    push rbx
    push r12
    
    lea r12, [g_TlsContext.DecryptionKey]
    
    ; CPUID (Processor brand string)
    mov eax, 80000002h
    cpuid
    mov [r12], eax
    mov [r12+4], ebx
    mov [r12+8], ecx
    mov [r12+12], edx
    
    mov eax, 80000003h
    cpuid
    mov [r12+16], eax
    mov [r12+20], ebx
    mov [r12+24], ecx
    mov [r12+28], edx
    
    ; Mix with timestamp
    rdtsc
    xor [r12], eax
    xor [r12+4], edx
    
    pop r12
    pop rbx
    ret
GenerateHardwareKey ENDP

