    xor ecx, ecx                    ; Security attributes
    xor edx, edx                    ; Default stack
    mov r8, offset BeaconThread     ; Start address
    mov r9, rbx                     ; Parameter
    
    mov qword ptr [rsp+20h], 0      ; Creation flags (0 = run immediately)
