    and eax, 0x3FFFFFFF             ; Random-ish
    xor edx, edx
    mov ecx, 40                     ; -20% to +20%
    div ecx
    sub eax, 20
    imul eax, [rbx+BEACON_CONFIG.BeaconInterval]
